LOGO_URL_BLACK = 'https://pnxhthrheqeucoisifjw.supabase.co/storage/v1/object/public/preventivi/logos/next_logo_black.png'

def _ensure_logo():
    """Estrae i loghi dal base64 hardcoded nel codice — sempre disponibile."""
    global _LOCAL_WHITE, _LOCAL_BLACK
    for b64, dst, attr in [
        (_LOGO_WHITE_B64, '/tmp/next_logo_white_embed.png', '_LOCAL_WHITE'),
        (_LOGO_BLACK_B64, '/tmp/next_logo_black_embed.png', '_LOCAL_BLACK'),
    ]:
        if not os.path.exists(dst):
            with open(dst,'wb') as f:
                f.write(_b64.b64decode(b64))
        globals()[attr] = dst


def draw_logo(c, x, y, h=8*mm, on_dark=True):
    _ensure_logo()
    # Usa il logo PNG reale (white su sfondo scuro, black su sfondo chiaro)
    logo = _LOCAL_WHITE if on_dark else _LOCAL_BLACK
    if logo and os.path.exists(logo):
        # Logo NEXT 645×80px → larghezza proporzionale all'altezza h
        logo_w = h * (645/80) * 0.90
        c.drawImage(logo, x, y, width=logo_w, height=h,
                    mask='auto', preserveAspectRatio=True)
        return
    # Fallback vettoriale se logo non disponibile
    fg = W if on_dark else G1; acc = G3 if on_dark else G2
    bw = h*1.4
    c.setFillColor(acc)
    c.roundRect(x, y, bw, h, h*0.12, fill=1, stroke=0)
    c.setStrokeColor(G1 if on_dark else W); c.setLineWidth(0.6)
    c.line(x+bw/2, y+h*0.12, x+bw/2, y+h*0.88)
    c.line(x+h*0.12, y+h/2, x+bw-h*0.12, y+h/2)
    c.setFillColor(fg); c.setFont("Helvetica-Bold", h*1.35)
    c.drawString(x+bw+h*0.28, y+h*0.22, "NEXT")
    c.setFillColor(acc); c.setFont("Helvetica", h*0.56)
    c.drawString(x+bw+h*0.28, y-h*0.04, "MOVE ENERGY")

