def make_irr_image(costo, flusso_ann, incremento):
    """IRR: layout con coordinate assolute in pollici — nessuna sovrapposizione."""
    import numpy_financial as _npf
    flussi = [-costo] + [round(flusso_ann*((1+incremento)**(t-1))) for t in range(1,11)]
    irr    = _npf.irr(flussi)
    irr_pct= round(irr*100, 2)
    fs     = flussi[1:]
    def _f(n): return f"{round(n):,}".replace(",",".")

    FW, FH = 7.4, 5.4   # larghezza × altezza in pollici
    PAD    = 0.12        # margine orizzontale

    fig = plt.figure(figsize=(FW, FH), facecolor='white')
    ax  = fig.add_axes([0,0,1,1])
    ax.set_facecolor('white'); ax.axis('off')
    ax.set_xlim(0, FW); ax.set_ylim(0, FH)   # coordinate in pollici

    def box(x, ytop, w, h, fc, ec, lw=1.2, r=0.07):
        """ytop = bordo superiore, h = altezza. Patch va da (x, ytop-h) a (x+w, ytop)."""
        ax.add_patch(FancyBboxPatch((x, ytop-h), w, h,
            boxstyle=f'round,pad={r}', facecolor=fc, edgecolor=ec, linewidth=lw, zorder=1))

    def t(x, y, s, **kw):
        ax.text(x, y, s, **kw)

    # ── TITOLO ─────────────────────────────────────────
    t(FW/2, FH-0.20, "Tasso Interno di Rendimento (IRR)",
      ha='center', va='top', fontsize=10.5, fontweight='bold', color=H['g1'])

    # ── DESCRIZIONE (2 righe esplicite, fontsize piccolo per sicurezza) ──
    t(FW/2, FH-0.52,
      "L\u2019IRR \u00e8 il rendimento annuo composto che azzera il Valore Attuale Netto"
      " dell\u2019investimento.",
      ha='center', va='center', fontsize=7.5, color=H['grm'])
    t(FW/2, FH-0.73,
      "Pi\u00f9 \u00e8 alto, pi\u00f9 l\u2019investimento \u00e8 conveniente rispetto"
      " ad alternative finanziarie di pari rischio.",
      ha='center', va='center', fontsize=7.5, color=H['grm'])

    # ── BOX FORMULA GENERICA (verde) — top a 4.85 ────
    B1_TOP = FH - 0.94    # 5.06
    B1_H   = 1.10
    box(PAD, B1_TOP, FW-PAD*2, B1_H, H['g5'], H['g2'], lw=1.4)
    t(FW/2, B1_TOP-0.32,
      r"$0 = -I + \sum_{t=1}^{n} \frac{CF_t}{(1+r)^t}$",
      ha='center', va='center', fontsize=13.5, color=H['g1'])
    # Variabili 3 col × 2 righe
    vars_ = [("$I$","Investimento iniziale"),("$CF_1\\!\\ldots\\!CF_n$","Benefici annui"),
              ("$r$","IRR — tasso cercato"), ("$t$","Anno (1\u2026n)"),
              ("$n$","Durata 10 anni"),("$NPV$","Val. att. netto\u00a0=\u00a00")]
    for vi,(sym,desc) in enumerate(vars_):
        col,row = vi%3, vi//3
        vx = 0.28+col*2.30; vy = B1_TOP-0.68-row*0.23
        t(vx, vy, sym+" = "+desc, ha='left', va='center', fontsize=7, color=H['grm'])

    # ── "Applicata al caso in esame" ───────────────────
    t(FW/2, B1_TOP-B1_H-0.16,
      "Applicata al caso in esame:",
      ha='center', va='center', fontsize=7.5, color=H['grm'], style='italic')

    # ── BOX FORMULA CON VALORI (oro) — top a 3.58 ────
    B2_TOP = B1_TOP-B1_H-0.32    # ≈ 3.62
    B2_H   = 0.78
    box(PAD, B2_TOP, FW-PAD*2, B2_H, H['abg'], H['au'], lw=1.4)
    l1 = ("$0 = -{} + ".format(_f(costo)) +
          " + ".join([f"\\dfrac{{{_f(v)}}}{{(1+r)^{{{i+1}}}}}" for i,v in enumerate(fs[:5])])+"$")
    l2 = ("$+ "+" + ".join([f"\\dfrac{{{_f(v)}}}{{(1+r)^{{{i+6}}}}}" for i,v in enumerate(fs[5:])])+"$")
    t(FW/2, B2_TOP-0.22, l1, ha='center', va='center', fontsize=8, color=H['g1'])
    t(FW/2, B2_TOP-0.55, l2, ha='center', va='center', fontsize=8, color=H['g1'])

    # ── Raccordo ────────────────────────────────────────
    t(FW/2, B2_TOP-B2_H-0.15,
      f"Incremento tariffe {incremento*100:.1f}%/anno \u2014 risolvendo numericamente per r:",
      ha='center', va='center', fontsize=7, color=H['grm'], style='italic')

    # ── BOX RISULTATO (verde scuro) — occupa lo spazio restante ─
    B3_TOP = B2_TOP-B2_H-0.30    # ≈ 2.52
    B3_BOT = 0.08
    B3_H   = B3_TOP - B3_BOT

    # Gradient verde scuro: #256040 (alto) → #152E24 (basso)
    _STEPS = 60
    _TOP_C = (0x25/255, 0x60/255, 0x40/255)   # #256040
    _BOT_C = (0x15/255, 0x2E/255, 0x24/255)   # #152E24
    for _i in range(_STEPS):
        _t = _i / _STEPS
        _cr = _TOP_C[0] + _t*(_BOT_C[0]-_TOP_C[0])
        _cg = _TOP_C[1] + _t*(_BOT_C[1]-_TOP_C[1])
        _cb = _TOP_C[2] + _t*(_BOT_C[2]-_TOP_C[2])
        _sh = B3_H / _STEPS
        _sy = B3_TOP - (_i+1)*_sh
        ax.add_patch(plt.Rectangle(
            (PAD, _sy), FW-PAD*2, _sh+0.02,
            facecolor=(_cr,_cg,_cb), edgecolor='none', zorder=1))
    # Bordo arrotondato sopra
    ax.add_patch(FancyBboxPatch(
        (PAD, B3_BOT), FW-PAD*2, B3_H,
        boxstyle='round,pad=0.07', facecolor='none',
        edgecolor='none', linewidth=0, zorder=2))

    mid = B3_BOT + B3_H/2     # centro verticale del box3

    t(FW/2, B3_TOP-0.18,
      "RISULTATO \u2014 Tasso Interno di Rendimento a 10 anni",
      ha='center', va='center', fontsize=8.5, fontweight='bold', color=H['g4'])

    # IRR grande
    t(FW/2, mid+0.38,
      f"{irr_pct}%",
      ha='center', va='center', fontsize=34, fontweight='bold', color=H['au'])
    t(FW/2, mid+0.06,
      "rendimento annuo composto",
      ha='center', va='center', fontsize=9, color=H['g4'])

    # 3 KPI
    chiavi=[(_f(costo),"investimento"),(_f(round(sum(fs))),"benefici 10 anni"),
            (_f(round(sum(fs)-costo)),"valore netto generato")]
    for i,(val,lbl) in enumerate(chiavi):
        cx = FW*0.17+i*FW*0.33
        t(cx, mid-0.38, f"\u20ac {val}", ha='center', va='center',
          fontsize=9.5, fontweight='bold', color=H['au'])
        t(cx, mid-0.60, lbl, ha='center', va='center',
          fontsize=7.5, color=H['g4'])
    t(FW/2, B3_BOT+0.12,
      "Rendimento superiore a qualsiasi strumento finanziario tradizionale a rischio equivalente.",
      ha='center', va='center', fontsize=7.5, color=H['g4'], style='italic')

    return _save(fig,'irr'), irr_pct


def make_confronto_html(irr_pct):
    strumenti = [
        ("Rendita Attiva Next (questa simulazione)", irr_pct,  "#1B4332", True,  "No"),
        ("BTP decennale",                            3.8,       "#52B788", False, "Sì"),
        ("Conto deposito vincolato",                 3.5,       "#52B788", False, "Parz."),
        ("Obbligazioni societarie IG",               4.5,       "#52B788", False, "Sì"),
        ("Fondi bilanciati (storico)",               5.5,       "#52B788", False, "Sì"),
        ("Azionario globale (storico)",              7.0,       "#52B788", False, "Sì"),
    ]
    max_r = irr_pct
    rows_html = ""
    for nome, pct, bar_col, is_next, liq in strumenti:
        bar_w = round(pct / max_r * 340)
        track_w = 340
        bg    = "#D8F3DC" if is_next else "white"
        fw    = "700" if is_next else "400"
        fs_nm = "13px" if is_next else "13px"
        pct_s = f"{pct:.1f}%"
        rows_html += f'''<tr style="background:{bg};border-bottom:1px solid #E8F5E9">
          <td style="padding:14px 18px;font-size:{fs_nm};font-weight:{fw};color:#1B4332;width:38%">{nome}</td>
          <td style="padding:14px 18px;width:42%">
            <div style="position:relative;height:12px;background:#ECEFF1;border-radius:6px;width:{track_w}px">
              <div style="position:absolute;top:0;left:0;height:12px;border-radius:6px;background:{bar_col};width:{bar_w}px"></div>
            </div>
          </td>
          <td style="padding:14px 18px;text-align:center;font-size:15px;font-weight:{fw};color:#1B4332;width:12%">{pct_s}</td>
          <td style="padding:14px 18px;text-align:center;font-size:13px;color:#78909C;width:8%">{liq}</td>
        </tr>'''

    html = f'''<!DOCTYPE html><html><head><meta charset="utf-8">
<style>*{{box-sizing:border-box;margin:0;padding:0}}
body{{font-family:Helvetica,Arial,sans-serif;background:white;width:794px}}
table{{border-collapse:collapse;width:100%}}
</style></head><body>
<div style="padding:0 13px">
<div style="font-size:10px;font-weight:700;color:#2D6A4F;letter-spacing:.08em;text-transform:uppercase;margin-bottom:10px;padding:0">
  Comparazione con strumenti finanziari alternativi
</div>
<div style="border:1px solid #B7E4C7;border-radius:10px;overflow:hidden">
  <div style="background:#1B4332;padding:14px 20px;display:table;width:100%">
    <span style="display:table-cell;color:white;font-size:16px;font-weight:700">Rendimento annuo — confronto diretto</span>
    <span style="display:table-cell;text-align:right;color:#52B788;font-size:13px;font-weight:600;vertical-align:middle">IRR calcolato vs benchmark di mercato</span>
  </div>
  <table>
    <thead>
      <tr style="background:#2D6A4F">
        <th style="padding:10px 18px;text-align:left;color:white;font-size:11px;font-weight:700;letter-spacing:.05em">Strumento</th>
        <th style="padding:10px 18px;text-align:center;color:white;font-size:11px;font-weight:700;letter-spacing:.05em">Rendimento visivo</th>
        <th style="padding:10px 18px;text-align:center;color:white;font-size:11px;font-weight:700;letter-spacing:.05em">Rend.&nbsp;%</th>
        <th style="padding:10px 18px;text-align:center;color:white;font-size:11px;font-weight:700;letter-spacing:.05em">Liquidit&agrave;</th>
      </tr>
    </thead>
    <tbody>{rows_html}</tbody>
  </table>
</div>
</div>
</body></html>'''

    hp = f"/tmp/confronto_{_ts()}.html"
    ip = f"/tmp/confronto_{_ts()}.png"
    with open(hp,"w") as f: f.write(html)
    subprocess.run(["wkhtmltoimage","--width","794","--quality","100",
                    "--format","png","--disable-smart-width",hp,ip],
                   capture_output=True)
    try: os.remove(hp)
    except: pass
    return ip


# ── 3. BENEFICIO CUMULATO 10/20 anni con composizione voci ─────────────────
def make_benefici_cumulato(ra, rr, rc, det, rsp, inc=0.03,
                            b10=None, b20=None):
    """Due barre: totale cumulato 10a e 20a, suddivise per voce."""
    plt.rcParams.update({'font.family':'DejaVu Sans'})
    fig, ax = plt.subplots(figsize=(7.4,3.2), facecolor='white')
    ax.set_facecolor('#F9FFFA')

    # Calcola cumulati per voce su 10 e 20 anni
    def cumul_voce(key, anni):
        tot = 0
        for y in range(1, anni+1):
            mlt = (1+inc)**(y-1)
            if key=='auto': tot += round(ra*mlt)
            elif key=='rid': tot += round(rr*mlt)
            elif key=='cer': tot += round(rc*mlt)
            elif key=='det': tot += (det if y<=10 else 0)
            elif key=='boll': tot += round(rsp*mlt)
        return tot

    voci   = ['auto','rid','cer','det','boll']
    labels_v = ['Autoconsumo','RID','CER','Detrazione','Bolletta']
    colors = ['#1B4332','#2D6A4F','#52B788','#E9C46A','#F4A261']
    bar_labels = ['10 anni','20 anni']

    data_10 = [cumul_voce(k,10) for k in voci]
    data_20 = [cumul_voce(k,20) for k in voci]

    x = [0, 1]
    width = 0.55
    bot_10, bot_20 = 0, 0
    bars_list = []
    for (key,col,lbl), v10, v20 in zip(zip(voci,colors,labels_v), data_10, data_20):
        b1 = ax.bar(0, v10, width, bottom=bot_10, color=col,
                    edgecolor='white', linewidth=0.8, label=lbl, zorder=3)
        b2 = ax.bar(1, v20, width, bottom=bot_20, color=col,
                    edgecolor='white', linewidth=0.8, zorder=3)
        # etichette dentro le barre
        for bar, v, bot in [(b1[0],v10,bot_10),(b2[0],v20,bot_20)]:
            if v > 200:
                ax.text(bar.get_x()+bar.get_width()/2,
                        bot+v/2,
                        f"€{v/1000:.0f}k",
                        ha='center',va='center',fontsize=7.5,
                        color='white',fontweight='bold',zorder=4)
        bot_10 += v10; bot_20 += v20

    tot10 = sum(data_10); tot20 = sum(data_20)
    for xi, tot in [(0,tot10),(1,tot20)]:
        ax.text(xi, tot+tot20*0.015,
                f"€ {tot/1000:.1f}k",
                ha='center', fontsize=11, fontweight='bold', color=H['g1'], zorder=5)

    ax.set_xticks([0,1])
    ax.set_xticklabels(['Cumulato 10 anni','Cumulato 20 anni'], fontsize=10, fontweight='bold', color=H['g1'])
    ax.set_ylabel("€ totali cumulati", fontsize=8.5, color=H['grm'])
    ax.yaxis.set_major_formatter(plt.FuncFormatter(lambda x,_:f"€{int(x/1000)}k"))
    ax.set_title("Beneficio economico totale cumulato — composizione per voce",
                 pad=8, fontsize=10, fontweight='bold', color=H['g1'])
    ax.tick_params(labelsize=9, bottom=False)
    ax.set_xlim(-0.5, 1.5)
    ax.grid(axis='y', alpha=0.5, lw=0.8, color='white', zorder=0)
    ax.spines['top'].set_visible(False); ax.spines['right'].set_visible(False)
    ax.spines['bottom'].set_visible(False)
    ax.spines['left'].set_color(H['gb2'])

    handles = [mpatches.Patch(color=c,label=l) for c,l in zip(colors,labels_v)]
    ax.legend(handles=handles, loc='upper center', fontsize=8, ncol=5,
              framealpha=0.95, edgecolor=H['gb2'],
              bbox_to_anchor=(0.5, -0.14))
    fig.tight_layout(pad=0.6)
    plt.subplots_adjust(bottom=0.22)
    return _save(fig,'benefici_cumulato')


# ── 4. PAYBACK elegante ───────────────────────────────────────────────────────
def make_payback_elegant(costo, b10, b11):
    plt.rcParams.update({'font.family':'DejaVu Sans'})
    fig, ax = plt.subplots(figsize=(7.4, 3.2), facecolor='white')
    ax.set_facecolor('#F9FFFA')

    anni = list(range(0,21)); vals=[0]; cum=0
    for a in range(1,21):
        cum += (b10 if a<=10 else b11); vals.append(cum)

    # area gradiente simulata con fill_between
    ax.fill_between(anni, vals, alpha=0.12, color=H['g2'], zorder=1)
    ax.fill_between(anni, [min(v,costo) for v in vals],
                    alpha=0.06, color=H['am'], zorder=0)

    # linea principale
    ax.plot(anni, vals, color=H['g1'], lw=2.8, zorder=4,
            solid_capstyle='round', solid_joinstyle='round')

    # markers anni chiave con stile migliorato
    for a in [5,10,15,20]:
        ax.scatter(a, vals[a], s=70, color='white', zorder=6,
                   edgecolors=H['g1'], linewidths=2.2)
        offset = max(vals)*0.046
        ax.annotate(f"€{vals[a]/1000:.0f}k",
                    xy=(a, vals[a]), xytext=(a, vals[a]+offset),
                    ha='center', fontsize=8, color=H['g1'], fontweight='bold',
                    bbox=dict(boxstyle='round,pad=0.20',
                              fc='white', ec=H['gb2'], lw=0.8),
                    arrowprops=None)

    # linea investimento
    ax.axhline(costo, color=H['am'], ls=(0,(6,3)), lw=2.0, zorder=3)
    ax.text(0.4, costo+max(vals)*0.022,
            f"Investimento iniziale: € {int(costo):,}".replace(",","."),
            fontsize=8.5, color=H['am'], fontweight='bold')

    # break-even
    bex = None
    for i in range(1,len(vals)):
        if vals[i-1] < costo <= vals[i]:
            frac=(costo-vals[i-1])/(vals[i]-vals[i-1])
            bex=anni[i-1]+frac
            ax.axvline(bex, color=H['ab'], ls=':', lw=2.0, alpha=0.85, zorder=3)
            ax.annotate(
                f"Break-even\n~{bex:.1f} anni",
                xy=(bex, costo), xytext=(bex+2.0, costo*0.68),
                fontsize=8.5, color=H['ab'], fontweight='bold',
                arrowprops=dict(arrowstyle='->', color=H['ab'], lw=1.5,
                                connectionstyle='arc3,rad=-0.15'),
                bbox=dict(boxstyle='round,pad=0.40',
                          fc=H['abg'], ec=H['ab'], lw=1.2))
            # zona in attivo
            ax.axvspan(bex, 20.5, alpha=0.06, color=H['g3'], zorder=0)
            mid = bex + (20-bex)*0.45
            ax.text(mid, max(vals)*0.52, "Zona in attivo",
                    ha='center', fontsize=8.5, color=H['g2'], alpha=0.9,
                    style='italic')
            break

    ax.set_title("Rientro dell'investimento — Beneficio cumulato su 20 anni",
                 pad=8, fontsize=10, fontweight='bold', color=H['g1'])
    ax.set_xlabel("Anni", fontsize=8.5, color=H['grm'])
    ax.set_ylabel("€ cumulati", fontsize=8.5, color=H['grm'])
    ax.yaxis.set_major_formatter(plt.FuncFormatter(lambda x,_:f"€{int(x/1000)}k"))
    ax.set_xlim(-0.5, 21.5)
    ax.set_ylim(-max(vals)*0.03, max(vals)*1.12)
    ax.tick_params(labelsize=8.5)
    ax.grid(True, alpha=0.4, lw=0.7, color=H['gb2'])
    ax.spines['top'].set_visible(False); ax.spines['right'].set_visible(False)
    ax.spines['left'].set_color(H['gb2']); ax.spines['bottom'].set_color(H['gb2'])

    fig.tight_layout(pad=0.5)
    return _save(fig,'payback')


