    global LOGO_PATH
    if logo_path: LOGO_PATH = logo_path

    filename=f"Report_{cliente}.pdf"
    oggi=datetime.date.today().strftime("%d/%m/%Y")
    anno=datetime.date.today().year
    num_off=f"PREV-{anno}-{abs(hash(cliente))%999999:06d}"

    ra = res.get("vantaggio_extra_autoconsumo", 0)
    rr = res.get("rid_annuo", 0)
    rc = res.get("cer_prudente", 0)
    rt = res.get("totale_benefici_annui", 0)
    det_ann = res.get("detrazione_annua", 0)
    vt = res.get("beneficio_annuale_totale", 0)
    rsp_boll = res.get("risparmio_bolletta", 0)
    risp_comp = res.get("risparmio_complessivo_annuo", 0)

    b10  = res["beneficio_10_anni"]; b20 = res["beneficio_20_anni"]
    van10= res["risparmio_complessivo_10"]; van20= res["risparmio_complessivo_20"]
    clip_pct = res.get("percentuale_clipping", 0)
    roi10 = int(((van10-costo_impianto)/costo_impianto)*100)
    pct_ben = int((b10/costo_impianto)*100)

    b_p10 = risp_comp
    b_p11 = (vt - det_ann) + rsp_boll

    cum=0; payback=0
    for a in range(1,31):
        bf=b_p10 if a<=10 else b_p11
        if cum+bf>=costo_impianto:
            payback=(a-1)+(costo_impianto-cum)/bf; break
        cum+=bf

    differenza_netto = van10 - costo_impianto
